/* Latin Securities brand artwork — inlined as base64 data URIs so the
   print preview window can render them synchronously. We tried serving
   the PNGs from /public for a bundle-size win, but Chrome's "Save as PDF"
   silently fails when images are still loading at save-time. Inline base64
   eliminates the race. */
export const LS_LOGO_POSITIVE_URL = "data:image/png;base64,";
export const LS_LOGO_NEGATIVE_URL = "data:image/png;base64,";
export const LS_LOGO_DATA_URL = LS_LOGO_POSITIVE_URL;

